    UnsupportedPlatform,
    /// Requested target was not found.
    NotFound,
    /// The OS denied access to the requested target.
    PermissionDenied,
    /// Caller supplied a malformed target or unsupported input value.
    InvalidInput,
    /// A child process or system command failed.
